                return false;
            }

            // 3. Type Check (Defensive for NoClasspath - Rule #2)
            CtExpression<?> arg = candidate.getArguments().get(0);
            CtTypeReference<?> type = arg.getType();

            // CRITICAL: NEVER assume type is not null in NoClasspath mode.
            // Check if valid.
            if (type != null) {
                // If it is already the new type (idempotency check), skip it.
                // TODO: Replace "NewType" with the qualified name of the target type
                if (type.getQualifiedName().contains("NewType")) {
                    return false;
                }

                // If it is a primitive, and we expect an object, handle logic here.
                // Or if we check for the old type:
                // TODO: Replace "OldType" with the qualified name of the source type
                if (!type.isPrimitive() && !type.getQualifiedName().contains("OldType") && !type.getQualifiedName().equals("<unknown>")) {
                    return false; 
                }
            }

            // 4. Owner/Scope Check
            CtTypeReference<?> owner = candidate.getExecutable().getDeclaringType();
            // TODO: Replace "TargetOwnerClass" with the class owning the method
            if (owner != null && !owner.getQualifiedName().contains("TargetOwnerClass") && !owner.getQualifiedName().equals("<unknown>")) {
                return false;
            }

            return true;
        }

