    public static void main(String[] args) {
        // Default paths
        String inputPath = "./src/main/java";
        String outputPath = "./src/main/gen";

        Launcher launcher = new Launcher();
        launcher.addInputResource(inputPath);
        launcher.setSourceOutputDirectory(outputPath);

        // CRITICAL IMPLEMENTATION RULE #1: Preserve Source Code (Robust Sniper Configuration)
        // Enable comments to be parsed
        launcher.getEnvironment().setCommentEnabled(true);
        // Force Sniper Printer manually to preserve exact formatting
        launcher.getEnvironment().setPrettyPrinterCreator(
            () -> new SniperJavaPrettyPrinter(launcher.getEnvironment())
        );

        // CRITICAL IMPLEMENTATION RULE #2: Defensive Coding (NoClasspath Compatibility)
        launcher.getEnvironment().setNoClasspath(true);

        // Add the processor
        launcher.addProcessor(new TemplateProcessor());

        try {
            launcher.run();
            System.out.println("Spoon processing complete. Output generated in: " + outputPath);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
